<form method="post" action="<?= e(url($formAction)); ?>">
    <?= csrf_field(); ?>
    <div class="row g-4">
        <div class="col-xl-8">
            <div class="card content-card mb-4"><div class="card-body p-4"><div class="form-section-title">Account Details</div><div class="row g-3"><div class="col-md-6"><label class="form-label">Role *</label><select name="role_id" class="form-select" required><option value="">Select role</option><?php foreach (($roles ?? []) as $role): ?><option value="<?= e((string) $role['id']); ?>" <?= (string) old('role_id', $userRecord['role_id'] ?? '') === (string) $role['id'] ? 'selected' : ''; ?>><?= e((string) $role['name']); ?> (<?= e((string) $role['code']); ?>)</option><?php endforeach; ?></select></div><div class="col-md-6"><label class="form-label">Linked Employee</label><select name="employee_id" class="form-select"><option value="">No employee link</option><?php foreach (($employees ?? []) as $employee): ?><option value="<?= e((string) $employee['id']); ?>" <?= (string) old('employee_id', $userRecord['employee_id'] ?? '') === (string) $employee['id'] ? 'selected' : ''; ?>><?= e((string) $employee['name']); ?></option><?php endforeach; ?></select></div><div class="col-md-6"><label class="form-label">First Name *</label><input type="text" name="first_name" class="form-control" value="<?= e((string) old('first_name', $userRecord['first_name'] ?? '')); ?>" required></div><div class="col-md-6"><label class="form-label">Last Name *</label><input type="text" name="last_name" class="form-control" value="<?= e((string) old('last_name', $userRecord['last_name'] ?? '')); ?>" required></div><div class="col-md-6"><label class="form-label">Email *</label><input type="email" name="email" class="form-control" value="<?= e((string) old('email', $userRecord['email'] ?? '')); ?>" required></div><div class="col-md-6"><label class="form-label">Account Status *</label><select name="status" class="form-select" required><?php foreach (['active' => 'Active', 'inactive' => 'Inactive', 'suspended' => 'Suspended'] as $value => $label): ?><option value="<?= e($value); ?>" <?= (string) old('status', $userRecord['status'] ?? 'active') === $value ? 'selected' : ''; ?>><?= e($label); ?></option><?php endforeach; ?></select></div><div class="col-md-6 d-flex align-items-end"><div class="form-check form-switch mb-2"><input class="form-check-input" type="checkbox" role="switch" id="must_change_password" name="must_change_password" value="1" <?= (int) old('must_change_password', $userRecord['must_change_password'] ?? 0) === 1 ? 'checked' : ''; ?>><label class="form-check-label" for="must_change_password">Require password change on next login</label></div></div></div></div></div>
            <div class="card content-card"><div class="card-body p-4"><div class="form-section-title">Password</div><div class="row g-3"><div class="col-md-6"><label class="form-label"><?= e($isEdit ? 'New Password' : 'Password *'); ?></label><input type="password" name="password" class="form-control" <?= $isEdit ? '' : 'required'; ?>></div><div class="col-md-6"><label class="form-label"><?= e($isEdit ? 'Confirm New Password' : 'Confirm Password *'); ?></label><input type="password" name="password_confirmation" class="form-control" <?= $isEdit ? '' : 'required'; ?>></div><div class="col-12"><p class="text-muted small mb-0"><?= e($isEdit ? 'Leave the password fields blank to keep the current password.' : \App\Support\PasswordPolicy::description()); ?></p></div></div></div></div>
