        <div class="col-xl-4">
            <div class="card content-card mb-4"><div class="card-body p-4"><h5 class="mb-2"><?= e($isEdit ? 'Update user account' : 'Create user account'); ?></h5><p class="text-muted small mb-4">Use this page to control login access separately from the employee master record.</p><?php if ($isEdit && (int) auth()->id() === (int) ($userRecord['id'] ?? 0)): ?><div class="alert alert-warning small">You are editing your own account. Role and status changes are blocked here to avoid session inconsistency.</div><?php endif; ?><div class="d-grid gap-2"><button type="submit" class="btn btn-primary"><?= e($submitLabel); ?></button><a href="<?= e(url('/admin/users')); ?>" class="btn btn-outline-secondary">Back to User Access</a></div></div></div>
            <?php if ($isEdit): ?><div class="card content-card mb-4"><div class="card-body p-4"><h6 class="mb-3">Current Link</h6><?php if (!empty($userRecord['employee_id'])): ?><div class="fw-semibold"><?= e((string) ($userRecord['employee_name'] ?? '')); ?></div><div class="small text-muted"><?= e((string) ($userRecord['employee_code'] ?? '')); ?></div><?php else: ?><div class="text-muted">No employee is currently linked to this account.</div><?php endif; ?></div></div><?php endif; ?>
            <?php if ($isEdit && !empty($userRecord['email'])): ?>
            <div class="card content-card"><div class="card-body p-4"><h6 class="mb-3"><i class="bi bi-envelope-paper"></i> Welcome Email</h6><p class="text-muted small mb-3">Generate a new secure password and send login credentials to <strong><?= e((string) $userRecord['email']); ?></strong>. The user will be required to change their password on first login.</p><form method="post" action="<?= e(url('/admin/users/' . (int) $userRecord['id'] . '/welcome-email')); ?>" onsubmit="return confirm('This will reset the user\'s password and email them new credentials. Continue?');"><?= csrf_field(); ?><div class="d-grid"><button type="submit" class="btn btn-outline-success"><i class="bi bi-send"></i> Send Welcome Email</button></div></form></div></div>
